export type StatsRange = 'week' | 'month';

export type DateRange = {
  from: string;
  to: string;
};

export type PracticeSummaryMetric = {
  id: string;
  label: string;
  value: string;
};

export type PracticeSummaryResult = {
  studentId: number;
  range: DateRange;
  metrics: PracticeSummaryMetric[];
  practiceMinutes: number;
  lessonMinutes: number;
};

export type VocabularyProgressResult = {
  addedWords: number;
  knownWords: number;
};

export type TrendBucket = {
  label: string;
  value: number;
};

export type TrendComparisonResult = {
  current: number;
  previous: number;
  delta: number;
  trend: 'improved' | 'declined' | 'flat';
  buckets: TrendBucket[];
};

